import os, re, json
wiki_root = 'wiki'
pages = {}
for dirpath, _, files in os.walk(wiki_root):
    for f in files:
        if f.endswith('.md'):
            pages[f[:-3]] = os.path.join(dirpath, f)
dead = set()
for title, path in pages.items():
    with open(path) as fh:
        content = fh.read()
    for link in re.findall(r'\\[\\[([^\\]|#\\\\\\\\]+)', content):
        link = link.strip()
        if '/' not in link and link not in pages:
            dead.add(link)
last_lint = 'unknown'
try:
    with open('wiki/hot.md') as fh:
        hot = fh.read()
    m = re.search(r'last_lint:\\s+(\\S+)', hot)
    if m: last_lint = m.group(1)
except: pass
print(json.dumps({'systemMessage': f'Wiki health: pages={len(pages)} | dead_links={len(dead)} | last_lint={last_lint}'}))" 2>/dev/null || true
